107: // ScopedAuthenticationServer is a grpc.Server which allows for specific scoped authentication.
108: type ScopedAuthenticationServer interface {
109: 	AllowsNamespaceScopedAuthentication(ctx context.Context) bool
110: }
111: 
112: // SkipsAuthenticationServer is a grpc.Server which should always skip authentication.
113: type SkipsAuthenticationServer interface {
114: 	SkipsAuthentication(ctx context.Context) bool
115: }
