140: // JWTInterceptorSelector is a grpc.UnaryServerInterceptor which selects requests
141: // which contain a JWT in the authorization header.
142: func JWTInterceptorSelector() selector.Matcher {
143: 	return selector.MatchFunc(func(ctx context.Context, _ interceptors.CallMeta) bool {
144: 		md, ok := metadata.FromIncomingContext(ctx)
145: 		if !ok {
146: 			return false
147: 		}
148: 
149: 		_, err := jwtFromMetadata(md)
150: 		return err == nil
151: 	})
152: }
