		// Create an HTTP request with a valid client token cookie
		req := httptest.NewRequest(http.MethodGet, "/api/test", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// ForwardCookies should extract the cookie and add it to metadata
		// However, there's a bug in the implementation
		md := method.ForwardCookies(context.Background(), req)

		// BUG: Line 49 of internal/server/authn/method/http.go always sets
		// md[stateCookieKey] instead of md[key]. This means:
		// 1. Token cookies are stored under the wrong key
		// 2. They overwrite state cookies
		// 3. gRPC middleware cannot extract the token

		// Check what was actually returned
		stateValues := md.Get("flipt_client_state")
		tokenValues := md.Get("flipt_client_token")

		if len(tokenValues) == 0 {
			// BUG: Token not found under correct key
			t.Logf("BUG CONFIRMED: flipt_client_token not in metadata")
			if len(stateValues) > 0 {
				t.Logf("Token was incorrectly stored under 'flipt_client_state' key instead")
				assert.Fail(t, "ForwardCookies bug: token stored under wrong metadata key")
			}
		}
	})

