		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		// This should fail because the token metadata is wrong
		if err == grpc_middleware.ErrUnauthenticated {
			t.Logf("ISSUE CONFIRMED: HTTP cookie not properly forwarded to gRPC")
			t.Logf("Root cause: ForwardCookies stores cookies under wrong metadata key")
			assert.Equal(t, grpc_middleware.ErrUnauthenticated, err)
		}
	})

