package main

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	grpc_middleware "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	"go.flipt.io/flipt/internal/server/authn/method"
	"go.flipt.io/flipt/internal/storage/authn"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	grpclib "google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression tests two authentication issues in Flipt:
// 1. Cookie tokens are not properly extracted from HTTP cookies
// 2. Server skip authentication mechanism validation
func TestRegression(t *testing.T) {
	t.Run("Issue1_CookieTokenExtractionBug", TestCookieTokenBug)
	t.Run("Issue2_ServerSkipAuthMechanism", TestServerSkipAuth)
}

// TestCookieTokenBug demonstrates the cookie extraction bug in ForwardCookies
// Location: internal/server/authn/method/http.go, lines 45-54
func TestCookieTokenBug(t *testing.T) {
	// Create a valid authentication token for testing
	authenticator := memory.NewStore()
	clientToken, _, err := authenticator.CreateAuthentication(
		context.TODO(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	t.Run("ForwardCookiesBugBehavior", func(t *testing.T) {
		// BUG LOCATION: internal/server/authn/method/http.go:49
		// Current code:
		//   for _, key := range []string{stateCookieKey, tokenCookieKey} {
		//       if cookie, err := req.Cookie(key); err == nil {
		//           md[stateCookieKey] = []string{cookie.Value}  // BUG: Always uses stateCookieKey
		//       }
		//   }
		// Should be:
		//   md[key] = []string{cookie.Value}

		// Create HTTP request with a token cookie (as a browser would send)
		req := httptest.NewRequest(http.MethodGet, "/api/evaluate", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// Call ForwardCookies to convert HTTP cookies to gRPC metadata
		md := method.ForwardCookies(context.Background(), req)

		// Expected: Token should be in metadata under key "flipt_client_token"
		// Actual (with bug): Token is stored under "flipt_client_state" key instead
		tokenValues := md.Get("flipt_client_token")
		stateValues := md.Get("flipt_client_state")

		// This assertion will fail, confirming the bug
		if len(tokenValues) == 0 && len(stateValues) > 0 {
			t.Logf("BUG CONFIRMED: Token stored under wrong key")
			t.Logf("Expected md[\"flipt_client_token\"], got md[\"flipt_client_state\"]")
			assert.Fail(t, "ForwardCookies stores cookies under wrong metadata key")
		}
	})

	t.Run("HTTPCookieNotForwardedToGRPC", func(t *testing.T) {
		// Scenario: Browser sends request with token in HTTP Set-Cookie header
		// HTTP gateway should convert to gRPC metadata using ForwardCookies
		// Due to bug, gRPC middleware cannot find the token

		logger := zaptest.NewLogger(t)
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Create HTTP request with cookie
		httpReq := httptest.NewRequest(http.MethodPost, "/api/evaluate", nil)
		httpReq.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: clientToken,
		})

		// ForwardCookies returns malformed metadata due to bug
		md := method.ForwardCookies(context.Background(), httpReq)
		ctx := metadata.NewIncomingContext(context.Background(), md)
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		// Try to authenticate with the malformed metadata
		_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		// Should fail because token is under wrong key
