		t.Run("BrowserCookieBypassFails", func(t *testing.T) {
			// A browser sends the cookie in HTTP Set-Cookie header
			// But the authentication middleware only checks Authorization header
			// and grpcgateway-cookie gRPC metadata

			md := metadata.MD{
				// Browser cookie is not being forwarded properly
				"flipt_client_token": []string{clientToken},
			}
			ctx := metadata.NewIncomingContext(context.Background(), md)
			srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

			_, err := grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
				ctx,
				nil,
				srv,
				handler,
			)

			// Fails because token is under wrong key for gRPC
			assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
				"Browser cookies not accepted due to missing ForwardCookies implementation")
		})
	})

	t.Run("ExpiredTokenRejected", func(t *testing.T) {
		logger := zaptest.NewLogger(t)

		// Create expired token
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-1 * time.Hour)),
			},
		)
		require.NoError(t, err)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}
		srv := &grpclib.UnaryServerInfo{Server: &mockServer{}}

		md := metadata.MD{
			"authorization": []string{"Bearer " + expiredToken},
		}
		ctx := metadata.NewIncomingContext(context.Background(), md)

		_, err = grpc_middleware.ClientTokenAuthenticationInterceptor(logger, authenticator)(
			ctx,
			nil,
			srv,
			handler,
		)

		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"expired token must be rejected")
	})
}

// TestServerSkipAuth tests the server skip authentication mechanism
func TestServerSkipAuth(t *testing.T) {
	logger := zaptest.NewLogger(t)

	t.Run("SkipsAuthenticationInterfaceWorks", func(t *testing.T) {
		// The SkipsAuthenticationServer interface allows servers to opt out
		// Location: internal/server/authn/middleware/grpc/middleware.go:112-115

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Server that implements SkipsAuthenticationServer
		server := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// Should NOT require authentication
		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server implementing SkipsAuthenticationServer should bypass auth requirement")
	})

	t.Run("WithServerSkipsAuthenticationOption", func(t *testing.T) {
		// The WithServerSkipsAuthentication option allows registering servers to skip auth
		// Location: internal/server/authn/middleware/grpc/middleware.go:97-105

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		server := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: server}

		// Register server to skip authentication
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(
			logger,
			grpc_middleware.WithServerSkipsAuthentication(server),
		)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err,
			"server in skip list should bypass authentication")
	})

	t.Run("ServerWithoutSkipRequiresAuth", func(t *testing.T) {
		// Potential issue: Servers not configured to skip will require authentication
		// This could be problematic for internal services like OIDC handlers

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		// Server without skip configuration
		server := &struct{}{}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		ctx := context.Background()
		_, err := interceptor(ctx, nil, srv, handler)

		// Will fail if not configured
		assert.Equal(t, grpc_middleware.ErrUnauthenticated, err,
			"server without skip configuration requires authentication")

		t.Logf("NOTE: Internal servers must be explicitly configured to skip authentication")
		t.Logf("This is done via SkipsAuthenticationServer interface or WithServerSkipsAuthentication option")
	})

	t.Run("SkipAuthPreservesAuthContext", func(t *testing.T) {
		// When a server skips authentication, it doesn't populate auth context
		// This is expected behavior

		authenticator := memory.NewStore()
		_, auth, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
		)
		require.NoError(t, err)

		// Handler checks for authentication context
		handlerCalled := false
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			handlerCalled = true
			retrieved := grpc_middleware.GetAuthenticationFrom(ctx)
			// When skipped, auth context may be nil
			return nil, nil
		}

		server := &mockServer{skipsAuth: true}
		srv := &grpclib.UnaryServerInfo{Server: server}
		interceptor := grpc_middleware.AuthenticationRequiredInterceptor(logger)

		// Call interceptor
		ctx := context.Background()
		_, err = interceptor(ctx, nil, srv, handler)

		assert.NoError(t, err)
		assert.True(t, handlerCalled, "handler should be called even when skipping auth")
	})
}

// mockServer implements SkipsAuthenticationServer interface for testing
type mockServer struct {
	skipsAuth bool
}

func (s *mockServer) SkipsAuthentication(ctx context.Context) bool {
	return s.skipsAuth
}
